func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	query := `
		SELECT u.display_name, a.action_type, COUNT(*) as total, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (` + placeholders(len(usernames)) + `) 
		AND a.created_at BETWEEN ? AND ?
	`

	args := make([]interface{}, 0, len(usernames)+2)
	for _, username := range usernames {
		args = append(args, username)
	}
	args = append(args, startDate, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var results []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":    true,
		"role":          true,
		"display_name":  true,
	}
	if !validFields[groupByField] {
		return nil, orm.ErrArgs
	}

	query := `
		SELECT u.` + groupByField + ` as group_value, 
		       COUNT(DISTINCT u.id) as user_count, 
		       COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (` + placeholders(len(departments)) + `)
		GROUP BY u.` + groupByField

	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		args[i] = dept
	}

	var results []orm.ParamsList
	_, err := o.Raw(query, args...).ValuesList(&results)
	if err != nil {
		return nil, err
	}

	// Convert ValuesList result to proper map format
	formattedResults := make([]map[string]interface{}, len(results))
	for i, row := range results {
		formattedResults[i] = map[string]interface{}{
			"group_value":      row[0],
			"user_count":       row[1],
			"total_activities": row[2],
		}
	}

	return formattedResults, nil
}

func placeholders(n int) string {
	if n <= 0 {
		return ""
	}
	placeholders := make([]byte, 0, 2*n-1)
	for i := 0; i < n; i++ {
		if i > 0 {
			placeholders = append(placeholders, ',')
		}
		placeholders = append(placeholders, '?')
	}
	return string(placeholders)
}

