	placeholders := make([]string, len(departments))
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		args[i] = dept
	}

	// Build SQL
	sql := fmt.Sprintf(`
		SELECT
			u.%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s`, groupByField, strings.Join(placeholders, ","), groupByField)

	rows, err := o.Raw(sql, args...).Rows()
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []map[string]interface{}
	for rows.Next() {
		var groupValue string
		var userCount, totalActivities int64
		err = rows.Scan(&groupValue, &userCount, &totalActivities)
		if err != nil {
			return nil, err
		}
		result := map[string]interface{}{
			"group_value":      groupValue,
			"user_count":       userCount,
			"total_activities": totalActivities,
		}
		results = append(results, result)
	}

