	"github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id

	return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	query := `
		SELECT u.display_name, a.action_type, COUNT(*) as total, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (` + placeholders(len(usernames)) + `) 
		AND a.created_at BETWEEN ? AND ?`

	params := make([]interface{}, 0, len(usernames)+2)
	for _, username := range usernames {
		params = append(params, username)
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		query += ` AND a.action_type = ?`
		params = append(params, actionTypeFilter)
	}

	query += ` GROUP BY u.display_name, a.action_type
	           ORDER BY u.display_name, a.action_type`

	var results []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":    true,
		"role":          true,
		"display_name":  true,
	}
	if !validFields[groupByField] {
		return nil, orm.ErrArgs
	}

	query := `
		SELECT u.` + groupByField + ` as group_value, 
		       COUNT(DISTINCT u.id) as user_count,
		       COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (` + placeholders(len(departments)) + `)
		GROUP BY u.` + groupByField

	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}

	var results []orm.Params
	_, err := o.Raw(query, params...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert orm.Params to map[string]interface{}
	stringResults := make([]map[string]interface{}, len(results))
	for i, result := range results {
		stringResults[i] = make(map[string]interface{})
		for k, v := range result {
			stringResults[i][k] = v
		}
	}

	return stringResults, nil
}

func placeholders(n int) string {
	if n == 0 {
		return ""
	}
	placeholders := make([]string, n)
	for i := 0; i < n; i++ {
		placeholders[i] = "?"
	}
	return "(" + join(placeholders, ",") + ")"
}

func join(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

