// Helper function to generate placeholders for IN clause
func generatePlaceholders(n int) string {
	if n == 0 {
		return ""
	}
	placeholders := make([]string, n)
	for i := 0; i < n; i++ {
		placeholders[i] = "?"
	}
	return "(" + joinStrings(placeholders, ",") + ")"
}

// Simple join function since we can't use strings.Join in this context without importing
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

